#include <bits/stdc++.h>    using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    int b=0;    int r=0;    cin >> n;    vi colors(n);    for (int i = 0; i < n; i++) {        cin >> colors[i];      }    int sum=accumulate(colors.begin(), colors.end(), 0);    if(sum%2==0){        cout<<"YES\n";    }else{        b=colors[0];         for (int i = 1; i < n; i++) {            if(colors[i]%2!=0){                b += colors[i];            }else{                r += colors[i];            }        }        if(b%2!=0 && r%2!=0){            cout<<"YES\n";        }else{            cout<<"NO\n";         }    }              } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}